import{_ as t,o as a,c as r,a5 as o}from"./chunks/framework.RItJKYA7.js";const u=JSON.parse('{"title":"Marketplace","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/marketplace.md","filePath":"reference/components/marketplace.md"}'),n={name:"reference/components/marketplace.md"};function i(s,e,d,l,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="marketplace" tabindex="-1">Marketplace <a class="header-anchor" href="#marketplace" aria-label="Permalink to &quot;Marketplace&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The <strong>Marketplace</strong> is the service-provider discovery and self-service installation hub for Platform Mesh. It allows workspace users to browse a catalog of available service providers (extensions), view their metadata, and install or uninstall them with a single click.</p><p>Under the hood, installing a provider creates a Kubernetes <code>APIBinding</code> in the current workspace that points at the provider&#39;s <code>APIExport</code>, granting the workspace access to the provider&#39;s APIs and controllers.</p><p>The key capabilities are:</p><ul><li><strong>Provider catalog</strong> — browsable, searchable, and filterable list of all available service providers</li><li><strong>Provider details</strong> — full metadata view: description, contacts, documentation, support channels, service level, and verification status</li><li><strong>Install</strong> — creates an <code>APIBinding</code> in the current workspace with all required permission claims auto-accepted</li><li><strong>Uninstall</strong> — deletes the <code>APIBinding</code> after a confirmation dialog</li><li><strong>Theme support</strong> — renders provider icons in light or dark variants based on the active SAP Fiori theme</li><li><strong>&quot;New&quot; badge</strong> — providers created less than 3 months ago are automatically tagged as new</li></ul><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>The Marketplace UI is a single-page Angular microfrontend loaded by Luigi inside an iframe, mounted at <code>/ui/marketplace/ui/</code>. It reads its runtime context (API gateway URL, account scope, auth token) from the Luigi <code>globalContext</code> and connects to the <a href="./kubernetes-graphql-gateway.html">Kubernetes GraphQL Gateway</a> to query <code>MarketplaceEntry</code> resources and execute <code>APIBinding</code> mutations.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Luigi globalContext</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Marketplace UI (iframe)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>GraphQL (Apollo) → Kubernetes GraphQL Gateway</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>MarketplaceEntry resources + APIBinding create/delete</span></span></code></pre></div><p><strong>Luigi navigation nodes</strong> registered by the UI:</p><table tabindex="0"><thead><tr><th>PathSegment</th><th>EntityType</th><th>Visibility</th><th>Purpose</th></tr></thead><tbody><tr><td><code>marketplace</code></td><td><code>main.core_platform-mesh_io_account</code></td><td>Visible (order 700)</td><td>Provider catalog listing</td></tr><tr><td><code>provider/:providerName</code></td><td>account</td><td>Hidden</td><td>Provider detail view</td></tr></tbody></table><p>The active <code>accountId</code> is forwarded from the Luigi context to every GraphQL request so that <code>spec.installed</code> reflects the binding state of the current workspace.</p><h2 id="technology-stack" tabindex="-1">Technology stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Framework</td><td>Angular 21</td></tr><tr><td>UI components</td><td>SAP Fundamental NGX 0.61</td></tr><tr><td>Micro-frontend orchestration</td><td>Luigi 2.22</td></tr><tr><td>State management</td><td>NgRx 21</td></tr><tr><td>GraphQL client</td><td>Apollo Angular / Apollo Client 4</td></tr><tr><td>Subscriptions transport</td><td>SSE (Server-Sent Events)</td></tr><tr><td>i18n</td><td>Angular localization (English, German)</td></tr><tr><td>Testing</td><td>Vitest 4</td></tr><tr><td>Language</td><td>TypeScript (ES2022, strict mode)</td></tr><tr><td>Container</td><td>nginx:alpine, served on port 8080</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The UI reads all runtime configuration from the Luigi node context injected by the Portal. No static environment files are required in production. The relevant context fields are:</p><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th></tr></thead><tbody><tr><td><code>portalContext.crdGatewayApiUrl</code></td><td>Base URL for the Kubernetes GraphQL Gateway</td></tr><tr><td><code>accountId</code></td><td>Current workspace scope for install/uninstall operations</td></tr><tr><td><code>token</code></td><td>Bearer token forwarded to every GraphQL request</td></tr><tr><td><code>analyticsTrackerConfig</code></td><td>Optional Matomo analytics configuration</td></tr></tbody></table><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/marketplace-ui" target="_blank" rel="noreferrer">github.com/platform-mesh/marketplace-ui</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./portal.html">Portal</a></li><li><a href="./kubernetes-graphql-gateway.html">Kubernetes GraphQL gateway</a></li><li><a href="./virtual-workspaces.html">virtual-workspaces</a> — serves the <code>MarketplaceEntry</code> view this UI consumes</li><li><a href="/pr-preview/pr-226/concepts/interaction-patterns/provider-to-consumer.html">Provider to consumer</a></li></ul>`,21)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
